spec.query:
SELECT mean(top) FROM (
    SELECT top(value, 5) FROM (
        SELECT year, month, value FROM "pvDailyEnergy"  TZ('$timezone')
    ) GROUP BY month, year TZ('$timezone')
) GROUP BY month, year TZ('$timezone')

SELECT top(value, 30) FROM (
        SELECT * FROM "pvDailyEnergy"  TZ('$timezone')
) GROUP BY year TZ('$timezone')
